#!/usr/bin/env node
// patch-logo.cjs — Nouveau logo Trengo (fichiers) + topbar texte + apparence Clair/Sombre.
const fs=require('fs'); const path=require('path'); const ROOT=process.cwd();
let ok=0,fail=0;
const good=m=>{console.log('  \u2705 '+m);ok++;};
const skip=m=>{console.log('  \u26a0\ufe0f  '+m);};
const err=m=>{console.log('  \u274c '+m);fail++;};
const read=r=>{const p=path.join(ROOT,r);return fs.existsSync(p)?fs.readFileSync(p,'utf8'):null;};
const write=(r,s)=>fs.writeFileSync(path.join(ROOT,r),s,'utf8');
function rep(r,from,to,l){const s=read(r);if(s==null){err('Introuvable: '+r);return;}if(s.includes(to)){good(l+' (déjà)');return;}if(!s.includes(from)){skip('Ancre manquante: '+l);return;}write(r,s.replace(from,to));good(l);}

console.log('\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
console.log('  PATCH — Logo Trengo');
console.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n');
console.log('[1] Fichiers image...');
try{ fs.writeFileSync(path.join(ROOT,'public/trengo-logo.png'),Buffer.from('','base64')); good('public/trengo-logo.png'); }catch(e){ err('public/trengo-logo.png: '+e.message); }
try{ fs.writeFileSync(path.join(ROOT,'public/icon-192.png'),Buffer.from('','base64')); good('public/icon-192.png'); }catch(e){ err('public/icon-192.png: '+e.message); }
try{ fs.writeFileSync(path.join(ROOT,'public/icon-512.png'),Buffer.from('','base64')); good('public/icon-512.png'); }catch(e){ err('public/icon-512.png: '+e.message); }
try{ fs.writeFileSync(path.join(ROOT,'public/icon-96.png'),Buffer.from('','base64')); good('public/icon-96.png'); }catch(e){ err('public/icon-96.png: '+e.message); }
try{ fs.writeFileSync(path.join(ROOT,'public/icon-192-maskable.png'),Buffer.from('','base64')); good('public/icon-192-maskable.png'); }catch(e){ err('public/icon-192-maskable.png: '+e.message); }
try{ fs.writeFileSync(path.join(ROOT,'public/icon-512-maskable.png'),Buffer.from('','base64')); good('public/icon-512-maskable.png'); }catch(e){ err('public/icon-512-maskable.png: '+e.message); }

console.log('\n[2] Code (topbar + apparence)...');
rep("src/components/Layout.jsx", `            <img src='/trengo-logo.png' alt="Trengo" style={{ width:44, height:44, objectFit:"contain" }}/>
            <span style={{ fontWeight: 900, fontSize: 18 }}><span style={{ color:'#1877F2' }}>tre</span><span style={{ color:'#FF2D8D' }}>ngo</span></span>`, `            <span style={{ fontWeight: 900, fontSize: 24, letterSpacing: -0.5 }}><span style={{ color:'#1877F2' }}>Tre</span><span style={{ color:'#FF2D8D' }}>ngo</span></span>`, "Topbar drawer: texte Trengo");
rep("src/components/Layout.jsx", `            <img src='/trengo-logo.png' alt="Trengo" style={{ width: 44, height: 44, objectFit: 'contain', flexShrink: 0 }} />
            <span style={{ fontWeight: 900, fontSize: 21, letterSpacing: -1, whiteSpace: 'nowrap' }}>
              <span style={{ color: '#1877F2' }}>tre</span><span style={{ color: '#FF2D8D' }}>ngo</span>
            </span>`, `            <span style={{ fontWeight: 900, fontSize: 28, letterSpacing: -1, whiteSpace: 'nowrap' }}>
              <span style={{ color: '#1877F2' }}>Tre</span><span style={{ color: '#FF2D8D' }}>ngo</span>
            </span>`, "Topbar principal: texte Trengo");
rep("src/pages/AppearanceSettings.jsx", `    label: 'Rose blanche',
    desc: 'Fond blanc, rose clair',`, `    label: 'Clair',
    desc: 'Fond clair',`, "Apparence: label Clair");
rep("src/pages/AppearanceSettings.jsx", `    label: 'Rose noire',
    desc: 'Fond sombre, accents roses',`, `    label: 'Sombre',
    desc: 'Fond sombre',`, "Apparence: label Sombre");
rep("src/pages/AppearanceSettings.jsx", `        <div style={{ width: 38, height: 38, background: 'white', borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800, fontSize: 20, color: '#1877F2' }}>T</div>`, `        <img src='/trengo-logo.png' alt="Trengo" style={{ width: 54, height: 54, objectFit: 'contain', background: 'white', borderRadius: 12, padding: 4 }} />`, "Apparence: logo PNG");
console.log('\n  Résultat: '+ok+' \u2705   '+fail+' \u274c');
if(fail===0) console.log('\n\ud83c\udf89 npx vite build\n'); else console.log('\n\u26a0\ufe0f envoie ce log.\n');
